  return els.map(e => {
    let n = e, chain = [];
    for (let i=0;i<4 && n;i++){ chain.push(n.tagName+(n.getAttribute('href')?`[href=${n.getAttribute('href')}]`:'')+(n.getAttribute('role')?`[role=${n.getAttribute('role')}]`:'')+(n.onclick?'[onclick]':'')+(n.className?`.${String(n.className).split(' ')[0]}`:'')); n=n.parentElement; }
    return chain.join(' < ');
  });
}

